@Luap99 
This is a proposal to change strUint.
How about branching on arguments?

```
var (
	MiB      = "MiB"
	GiB      = "GiB"
)

response.Memory = strUint(vm.Memory, MiB, false) // or true
response.DiskSize = strUint(vm.DiskSize, GiB, false) // or true

func strUint(u uint64, unit string, isHuman bool) string {
	var bytes strongunits.B
	switch unit {
	case "MiB":
		// Convert MiB to bytes
		bytes = strongunits.MiB(u).ToBytes()
	case "GiB":
		// Convert GiB to bytes
		bytes = strongunits.GiB(u).ToBytes()
	default:
		// Handle unexpected unit type
		return ""
	}

	if isHuman {
		// Convert bytes to human-readable format
		return units.BytesSize(float64(bytes))
	} else {
		// Convert bytes to string
		return strconv.FormatUint(uint64(bytes), 10)
	}
}
```

